### Unit Tests

```rust
#[cfg(test)]
mod read_line_limited_tests {
    use super::*;
    use std::io::Cursor;

    #[test]
    fn test_normal_input_within_limit() {
        let mut reader = Cursor::new("hello world\n");
        let result = read_line_limited(&mut reader, 100).unwrap();
        assert_eq\!(result, "hello world\n");
    }

    #[test]
    fn test_input_exactly_at_limit() {
        let input = "ab\n"; // 3 bytes
        let mut reader = Cursor::new(input);
        let result = read_line_limited(&mut reader, 3).unwrap();
        assert_eq\!(result, "ab\n");
    }

    #[test]
    fn test_input_exceeds_limit() {
        let mut reader = Cursor::new("this is a long input\n");
        let result = read_line_limited(&mut reader, 5);
        assert\!(matches\!(result, Err(PromptError::InputTooLong { limit: 5, .. })));
    }

    #[test]
    fn test_empty_input_eof() {
        let mut reader = Cursor::new("");
        let result = read_line_limited(&mut reader, 100);
        assert\!(matches\!(result, Err(PromptError::Eof)));
    }

    #[test]
    fn test_input_without_newline_eof() {
        let mut reader = Cursor::new("no newline");
        let result = read_line_limited(&mut reader, 100).unwrap();
        assert_eq\!(result, "no newline");
    }

    #[test]
    fn test_empty_line() {
        let mut reader = Cursor::new("\n");
        let result = read_line_limited(&mut reader, 100).unwrap();
        assert_eq\!(result, "\n");
    }

    #[test]
    fn test_unicode_input() {
        let mut reader = Cursor::new("héllo 世界\n");
        let result = read_line_limited(&mut reader, 100).unwrap();
        assert_eq\!(result, "héllo 世界\n");
    }

    #[test]
    fn test_invalid_utf8() {
        let invalid = vec\![0xff, 0xfe, b'\n']; // Invalid UTF-8
        let mut reader = Cursor::new(invalid);
        let result = read_line_limited(&mut reader, 100);
        assert\!(matches\!(result, Err(PromptError::InvalidInput(_))));
    }
}
